import{_ as t,o as i,c as o,ae as a}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"The Autonomous Brain: Strategic Execution","description":"","frontmatter":{},"headers":[],"relativePath":"docs/architecture/autonomous-brain.md","filePath":"docs/architecture/autonomous-brain.md"}'),r={name:"docs/architecture/autonomous-brain.md"};function n(s,e,c,l,u,h){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="the-autonomous-brain-strategic-execution" tabindex="-1">The Autonomous Brain: Strategic Execution <a class="header-anchor" href="#the-autonomous-brain-strategic-execution" aria-label="Permalink to &quot;The Autonomous Brain: Strategic Execution&quot;">​</a></h1><p>The xB77 agent manages a hybrid execution pipeline, choosing the most efficient and private route for every transaction.</p><h2 id="_1-multi-rail-privacy" tabindex="-1">1. Multi-Rail Privacy <a class="header-anchor" href="#_1-multi-rail-privacy" aria-label="Permalink to &quot;1. Multi-Rail Privacy&quot;">​</a></h2><p>Instead of a single payment method, the agent routes funds through specialized protocols depending on the risk and privacy requirements:</p><ul><li><strong>Shielded Payments (ShadowWire):</strong> The default rail for secure B2B transactions. Uses stealth-like logic to decouple sender and receiver.</li><li><strong>Obfuscated Flows (Privacy Cash):</strong> For transactions requiring high anonymity, the agent routes funds through a liquidity pool to break chain-link analysis.</li><li><strong>ZK-Compressed Receipts (Light Protocol):</strong> Every transaction, regardless of the rail, generates a compressed receipt. This ensures that the agent&#39;s history is stored on-chain but remains invisible to public explorers.</li></ul><h2 id="_2-decision-logic" tabindex="-1">2. Decision Logic <a class="header-anchor" href="#_2-decision-logic" aria-label="Permalink to &quot;2. Decision Logic&quot;">​</a></h2><p>When an intent is received via <strong>MCP</strong>, the <code>PaymentStrategyEngine</code> performs:</p><ol><li><strong>Forensic Scan:</strong> Checks the destination address via Helius/Range simulation.</li><li><strong>Route Selection:</strong><ul><li>Low Risk -&gt; ShadowWire (Fast &amp; Shielded).</li><li>High Privacy Need -&gt; Privacy Cash (Pool Obfuscation).</li><li>Critical Value -&gt; <strong>Ghost Mode</strong> (Burner wallet relay).</li></ul></li><li><strong>Governance Check:</strong> If the amount exceeds the autonomous limit, it triggers a <strong>Lockdown</strong> in the Hub.</li></ol>',8)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
